import React, { useEffect, useState } from "react";
import socket from "../socket";

function Host() {
  const [gamePin, setGamePin] = useState("");
  const [players, setPlayers] = useState([]);
  const [leaderboard, setLeaderboard] = useState([]);

  useEffect(() => {
    socket.on("gameCreated", (data) => {
      const pin = data?.gamePin || data?.gameId || data;
      setGamePin(pin);
    });

    socket.on("playersUpdated", (data) => {
      setPlayers(data || []);
    });

    socket.on("playerJoined", (data) => {
      setPlayers(data || []);
    });

    socket.on("leaderboardUpdated", (data) => {
      setLeaderboard(data || []);
    });

    socket.on("leaderboard", (data) => {
      setLeaderboard(data || []);
    });

    socket.on("updateScores", (data) => {
      setLeaderboard(data || []);
    });

    return () => {
      socket.off("gameCreated");
      socket.off("playersUpdated");
      socket.off("playerJoined");
      socket.off("leaderboardUpdated");
      socket.off("leaderboard");
      socket.off("updateScores");
    };
  }, []);

  const createGame = () => {
  console.log("Create Game clicked");
  alert("Create Game clicked");
  socket.emit("createGame");
  };

  const startGame = () => {
    if (!gamePin) {
      alert("Create game first");
      return;
    }

    socket.emit("startGame", gamePin);
  };

  return (
    <div style={{ padding: "30px", fontFamily: "Arial" }}>
      <h1>Host</h1>

      {!gamePin && <button onClick={createGame}>Create Game</button>}

      {gamePin && (
        <>
          <h2>
            Game PIN: <span style={{ color: "green" }}>{gamePin}</span>
          </h2>

          <button onClick={startGame}>Start Game</button>
        </>
      )}

      <hr />

      <h2>Joined Players</h2>

      {(players || []).length === 0 ? (
        <p>No players joined yet</p>
      ) : (
        (players || []).map((player, index) => (
          <p key={index}>
            {index + 1}. {player.name || player.playerName || player}
          </p>
        ))
      )}

      <hr />

      <h2>Leaderboard</h2>

      {(leaderboard || []).length === 0 ? (
        <p>No scores yet</p>
      ) : (
        (leaderboard || []).map((player, index) => (
          <p key={index}>
            {index + 1}. {player.name || player.playerName || "Player"} -{" "}
            {player.score || 0}
          </p>
        ))
      )}
    </div>
  );
}

export default Host;
